SELECT e.*, ste.site_nm AS site_nm, cd_et.code_label AS event_type_cd_nm, cd_es.code_label AS event_status_cd_nm, cd_et2.code_label AS target_type_cd_nm FROM pm_event e LEFT JOIN sy_site ste ON ste.site_id = e.site_id LEFT JOIN sy_code cd_et ON cd_et.code_grp = 'EVENT_TYPE' AND cd_et.code_value = e.event_type_cd LEFT JOIN sy_code cd_es ON cd_es.code_grp = 'EVENT_STATUS' AND cd_es.code_value = e.event_status_cd LEFT JOIN sy_code cd_et2 ON cd_et2.code_grp = 'EVENT_TARGET' AND cd_et2.code_value = e.target_type_cd
ORDER BY e.event_id ASC ORDER BY e.event_id DESC ORDER BY e.event_nm ASC ORDER BY e.event_nm DESC ORDER BY e.reg_date ASC ORDER BY e.reg_date DESC ORDER BY e.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

